14	}
15	
16	const authStore = useAuthStore();
17	const loading = ref(false);
18	
19	const adminStats = ref<DashboardStats>({
20	  totalSessions: 0,
21	  upcomingSessions: 0,
22	  pendingReviews: 0,
23	  failedJobs: 0,
