30	    subjectName: string;
31	    examDate: string;
32	    startTime: string;
33	    roomName: string;
34	  }>
35	>([]);
36	
37	const isStudent = computed(() => authStore.activeRole === "STUDENT");
38	
39	onMounted(async () => {
40	  loading.value = true;
41	  try {
42	    if (isStudent.value) {
43	      exams.value = await unwrap(api.get("/my/exams"));
44	    } else {
45	      adminStats.value = await unwrap(api.get("/dashboard/stats"));
46	    }
