1	import { computed, ref } from "vue";
2	import { defineStore } from "pinia";
3	import { api, unwrap } from "@/api";
4	import type { PageData } from "@/types/api";
5	
6	export interface InboxMessage {
7	  deliveryId: number;
8	  notificationId: number;
9	  title: string;
10	  body: string;
11	  eventType: string;
12	  priority: string;
13	  deliveredAt: string;
14	  read: boolean;
15	}
16	
17	export const useNotificationsStore = defineStore("notifications", () => {
18	  const inbox = ref<PageData<InboxMessage> | null>(null);
19	  const unread = ref(0);
20	  const loading = ref(false);
21	
22	  const hasUnread = computed(() => unread.value > 0);
23	
24	  async function fetchInbox(
25	    page = 1,
26	    size = 20,
27	    read?: boolean,
28	  ): Promise<void> {
29	    loading.value = true;
30	    try {
31	      inbox.value = await unwrap(
32	        api.get<PageData<InboxMessage>>("/inbox", {
33	          params: { page, size, read },
34	        }),
35	      );
36	    } finally {
37	      loading.value = false;
38	    }
39	  }
40	
41	  async function fetchUnreadCount(): Promise<void> {
42	    const data = await unwrap(
43	      api.get<{ unreadCount: number }>("/inbox/unread-count"),
44	    );
45	    unread.value = data.unreadCount;
46	  }
