@import "@/assets/theme.css";

* {
  box-sizing: border-box;
}

html,
body,
#app {
  margin: 0;
  min-height: 100%;
}

body {
  font-family: var(--font-body);
  color: var(--color-text);
  background: radial-gradient(
      circle at 20% 10%,
      rgba(9, 132, 227, 0.1),
      transparent 36%
    ),
    radial-gradient(circle at 80% 0, rgba(0, 184, 148, 0.08), transparent 32%),
    linear-gradient(180deg, #f3f9ff 0%, #f8fafc 60%, #ecf5f3 100%);
  line-height: 1.4;
}

a {
  color: inherit;
}

button,
input,
select,
textarea {
  font: inherit;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  margin: -1px;
  padding: 0;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

.card {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: 16px;
  box-shadow: var(--shadow-card);
}

