5	import { api, unwrap } from "@/api";
6	import { useAuthStore } from "@/stores/auth";
7	
8	const route = useRoute();
9	const authStore = useAuthStore();
10	const id = Number(route.params.id);
11	
12	const loading = ref(false);
13	const detail = ref<Record<string, unknown> | null>(null);
14	const versions = ref<Array<{ id: number; label: string }>>([]);
15	
16	const allowRestore = computed(() =>
17	  ["ADMIN", "ACADEMIC_AFFAIRS"].includes(authStore.activeRole),
18	);
19	
20	async function loadDetail(): Promise<void> {
21	  loading.value = true;
22	  try {
23	    detail.value = await unwrap(api.get(`/sessions/${id}`));
24	    const history = await unwrap(
25	      api.get("/versions", {
26	        params: { entityType: "EXAM_SESSION", entityId: id },
27	      }),
28	    );
29	    versions.value = (history.items || []).map(
30	      (item: { id: number; versionNumber: number }) => ({
31	        id: item.id,
32	        label: `版本 v${item.versionNumber}`,
33	      }),
34	    );
35	  } finally {
36	    loading.value = false;
37	  }
38	}
39	
40	async function fetchDiff(leftId: number, rightId: number) {
41	  const data = await unwrap(
42	    api.get("/versions/compare", {
43	      params: { versionA: leftId, versionB: rightId },
44	    }),
45	  );
46	  return (data.diffs || []).map(
47	    (item: { field: string; oldValue: string; newValue: string }) => ({
48	      fieldName: item.field,
49	      oldValue: item.oldValue,
50	      newValue: item.newValue,
51	    }),
52	  );
53	}
54	
55	async function restore(versionId: number): Promise<void> {
56	  await unwrap(api.post(`/versions/${versionId}/restore`));
57	  await loadDetail();
58	}
59	
60	onMounted(() => {
