import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class NotificationDeliveryPipelineTest {

    @Mock
    private NotificationRepository notificationRepository;
    @Mock
    private NotifDeliveryRepository deliveryRepository;
    @Mock
    private NotifPreferenceRepository preferenceRepository;
    @Mock
    private SysUserRepository userRepository;
    @Mock
    private JobQueueService jobQueueService;
    @Mock
    private NotificationTargetResolver targetResolver;

    private NotificationScopeParser scopeParser;
    private AtomicLong deliveryId;
    private Map<Long, NotifDelivery> store;

    @BeforeEach
    void setup() {
        scopeParser = new NotificationScopeParser(new ObjectMapper());
        deliveryId = new AtomicLong(1);
        store = new HashMap<>();
        when(deliveryRepository.save(any(NotifDelivery.class))).thenAnswer(invocation -> {
            NotifDelivery d = invocation.getArgument(0);
            if (d.getId() == null) {
                d.setId(deliveryId.getAndIncrement());
            }
            store.put(d.getId(), d);
            return d;
        });
    }

    private NotificationDeliveryPipeline createPipeline(List<NotificationDeliveryStrategy> strategies) {
        return new NotificationDeliveryPipeline(
                notificationRepository,
                deliveryRepository,
                preferenceRepository,
                userRepository,
                jobQueueService,
                targetResolver,
                scopeParser,
                strategies
        );
    }

    @Test
    void shouldEnqueueJobOnPublishedEvent() {
        Notification notification = notification("HIGH");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(jobQueueService.enqueue(any(), anyString(), anyString())).thenReturn(new JobRecord());

        NotificationDeliveryPipeline pipeline = createPipeline(List.of(alwaysSuccessApp()));
        pipeline.onPublished(new NotificationPublishedEvent(100L));

        verify(jobQueueService).enqueue(any(), anyString(), anyString());
    }

    @Test
    void shouldHoldMediumPriorityDeliveryDuringDndWindow() {
        Notification notification = notification("MEDIUM");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(targetResolver.resolveStudentRecipientIds(any())).thenReturn(Set.of(10L));
        when(userRepository.findById(10L)).thenReturn(Optional.of(student(10L, null)));
        LocalTime now = LocalTime.now();
        when(preferenceRepository.findByUserIdAndEventType(10L, notification.getEventType()))
                .thenReturn(Optional.of(pref(true, now.minusMinutes(1), now.plusMinutes(1))));

        NotificationDeliveryPipeline pipeline = createPipeline(List.of(alwaysSuccessApp(), unavailableWechat()));

        JobRecord job = new JobRecord();
        job.setPayloadJson("{\"notificationId\":100}");
        pipeline.executeNotificationSend(job);

        NotifDelivery delivery = store.values().iterator().next();
        assertEquals(DeliveryStatus.HELD_DND, delivery.getStatus());
    }

    @Test
    void shouldCreateRetryJobWhenDeliveryFails() {
        Notification notification = notification("HIGH");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(targetResolver.resolveStudentRecipientIds(any())).thenReturn(Set.of(10L));
        when(userRepository.findById(10L)).thenReturn(Optional.of(student(10L, null)));
        when(preferenceRepository.findByUserIdAndEventType(10L, notification.getEventType()))
                .thenReturn(Optional.of(pref(true, null, null)));
        when(jobQueueService.enqueue(any(), anyString(), anyString(), any(LocalDateTime.class))).thenReturn(new JobRecord());

        NotificationDeliveryPipeline pipeline = createPipeline(List.of(alwaysFailApp(), unavailableWechat()));

        JobRecord job = new JobRecord();
        job.setPayloadJson("{\"notificationId\":100}");
        pipeline.executeNotificationSend(job);

        NotifDelivery delivery = store.values().iterator().next();
        assertEquals(DeliveryStatus.PENDING, delivery.getStatus());
        assertEquals(1, delivery.getAttempts());
        verify(jobQueueService, atLeastOnce()).enqueue(any(), anyString(), anyString(), any(LocalDateTime.class));
    }

    @Test
    void shouldFallbackToInAppWhenWechatUnavailable() {
        Notification notification = notification("HIGH");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(targetResolver.resolveStudentRecipientIds(any())).thenReturn(Set.of(10L));
        when(userRepository.findById(10L)).thenReturn(Optional.of(student(10L, "wx-token")));
        when(preferenceRepository.findByUserIdAndEventType(10L, notification.getEventType()))
                .thenReturn(Optional.of(pref(true, null, null)));

