        NotifPreference pref = new NotifPreference();
        pref.setEnabled(enabled);
        pref.setDndStart(start);
        pref.setDndEnd(end);
        return pref;
    }

    private NotificationDeliveryStrategy alwaysSuccessApp() {
        return new NotificationDeliveryStrategy() {
            @Override public NotificationChannel channel() { return NotificationChannel.APP; }
            @Override public boolean supports(SysUser user) { return true; }
            @Override public DeliveryAttemptResult deliver(Notification notification, NotifDelivery delivery, SysUser user) {
                return DeliveryAttemptResult.success();
            }
        };
    }

    private NotificationDeliveryStrategy alwaysFailApp() {
        return new NotificationDeliveryStrategy() {
            @Override public NotificationChannel channel() { return NotificationChannel.APP; }
            @Override public boolean supports(SysUser user) { return true; }
            @Override public DeliveryAttemptResult deliver(Notification notification, NotifDelivery delivery, SysUser user) {
                return DeliveryAttemptResult.failed("app failure");
            }
        };
    }

    private NotificationDeliveryStrategy unavailableWechat() {
        return new NotificationDeliveryStrategy() {
            @Override public NotificationChannel channel() { return NotificationChannel.WECHAT; }
            @Override public boolean supports(SysUser user) { return user.getDeviceToken() != null; }
            @Override public DeliveryAttemptResult deliver(Notification notification, NotifDelivery delivery, SysUser user) {
                return DeliveryAttemptResult.unavailable("wechat down");
            }
        };
    }
}

