package com.exam.system.service;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.atLeastOnce;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

import com.exam.system.dto.notification.NotificationTargetScopeDto;
import com.exam.system.entity.JobRecord;
import com.exam.system.entity.NotifDelivery;
import com.exam.system.entity.NotifPreference;
import com.exam.system.entity.Notification;
import com.exam.system.entity.NotificationChannel;
import com.exam.system.entity.SysRole;
import com.exam.system.entity.SysUser;
import com.exam.system.notification.DeliveryStatus;
import com.exam.system.notification.NotificationPublishedEvent;
import com.exam.system.notification.NotificationStatus;
import com.exam.system.job.JobQueueService;
import com.exam.system.repository.NotifDeliveryRepository;
import com.exam.system.repository.NotifPreferenceRepository;
import com.exam.system.repository.NotificationRepository;
import com.exam.system.repository.SysUserRepository;
import com.exam.system.service.impl.delivery.DeliveryAttemptResult;
import com.exam.system.service.impl.delivery.NotificationDeliveryStrategy;
import com.exam.system.service.impl.notification.NotificationDeliveryPipeline;
import com.exam.system.service.impl.notification.NotificationScopeParser;
import com.exam.system.service.impl.notification.NotificationTargetResolver;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.Set;
import java.util.concurrent.atomic.AtomicLong;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;

@ExtendWith(MockitoExtension.class)
class NotificationDeliveryPipelineTest {

    @Mock
    private NotificationRepository notificationRepository;
    @Mock
    private NotifDeliveryRepository deliveryRepository;
    @Mock
    private NotifPreferenceRepository preferenceRepository;
    @Mock
    private SysUserRepository userRepository;
    @Mock
    private JobQueueService jobQueueService;
    @Mock
    private NotificationTargetResolver targetResolver;

    private NotificationScopeParser scopeParser;
    private AtomicLong deliveryId;
    private Map<Long, NotifDelivery> store;

    @BeforeEach
    void setup() {
        scopeParser = new NotificationScopeParser(new ObjectMapper());
        deliveryId = new AtomicLong(1);
        store = new HashMap<>();
        when(deliveryRepository.save(any(NotifDelivery.class))).thenAnswer(invocation -> {
            NotifDelivery d = invocation.getArgument(0);
            if (d.getId() == null) {
                d.setId(deliveryId.getAndIncrement());
            }
            store.put(d.getId(), d);
            return d;
        });
    }

    private NotificationDeliveryPipeline createPipeline(List<NotificationDeliveryStrategy> strategies) {
        return new NotificationDeliveryPipeline(
                notificationRepository,
                deliveryRepository,
                preferenceRepository,
                userRepository,
                jobQueueService,
                targetResolver,
                scopeParser,
                strategies
        );
    }

    @Test
    void shouldEnqueueJobOnPublishedEvent() {
        Notification notification = notification("HIGH");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(jobQueueService.enqueue(any(), anyString(), anyString())).thenReturn(new JobRecord());

        NotificationDeliveryPipeline pipeline = createPipeline(List.of(alwaysSuccessApp()));
        pipeline.onPublished(new NotificationPublishedEvent(100L));

        verify(jobQueueService).enqueue(any(), anyString(), anyString());
    }

    @Test
    void shouldHoldMediumPriorityDeliveryDuringDndWindow() {
        Notification notification = notification("MEDIUM");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(targetResolver.resolveStudentRecipientIds(any())).thenReturn(Set.of(10L));
        when(userRepository.findById(10L)).thenReturn(Optional.of(student(10L, null)));
        LocalTime now = LocalTime.now();
        when(preferenceRepository.findByUserIdAndEventType(10L, notification.getEventType()))
                .thenReturn(Optional.of(pref(true, now.minusMinutes(1), now.plusMinutes(1))));

        NotificationDeliveryPipeline pipeline = createPipeline(List.of(alwaysSuccessApp(), unavailableWechat()));

        JobRecord job = new JobRecord();
        job.setPayloadJson("{\"notificationId\":100}");
        pipeline.executeNotificationSend(job);

        NotifDelivery delivery = store.values().iterator().next();
        assertEquals(DeliveryStatus.HELD_DND, delivery.getStatus());
    }

    @Test
    void shouldCreateRetryJobWhenDeliveryFails() {
        Notification notification = notification("HIGH");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(targetResolver.resolveStudentRecipientIds(any())).thenReturn(Set.of(10L));
        when(userRepository.findById(10L)).thenReturn(Optional.of(student(10L, null)));
        when(preferenceRepository.findByUserIdAndEventType(10L, notification.getEventType()))
                .thenReturn(Optional.of(pref(true, null, null)));
        when(jobQueueService.enqueue(any(), anyString(), anyString(), any(LocalDateTime.class))).thenReturn(new JobRecord());

        NotificationDeliveryPipeline pipeline = createPipeline(List.of(alwaysFailApp(), unavailableWechat()));

        JobRecord job = new JobRecord();
        job.setPayloadJson("{\"notificationId\":100}");
        pipeline.executeNotificationSend(job);

        NotifDelivery delivery = store.values().iterator().next();
        assertEquals(DeliveryStatus.PENDING, delivery.getStatus());
        assertEquals(1, delivery.getAttempts());
        verify(jobQueueService, atLeastOnce()).enqueue(any(), anyString(), anyString(), any(LocalDateTime.class));
    }

    @Test
    void shouldFallbackToInAppWhenWechatUnavailable() {
        Notification notification = notification("HIGH");
        when(notificationRepository.findById(100L)).thenReturn(Optional.of(notification));
        when(targetResolver.resolveStudentRecipientIds(any())).thenReturn(Set.of(10L));
        when(userRepository.findById(10L)).thenReturn(Optional.of(student(10L, "wx-token")));
        when(preferenceRepository.findByUserIdAndEventType(10L, notification.getEventType()))
                .thenReturn(Optional.of(pref(true, null, null)));

        NotificationDeliveryPipeline pipeline = createPipeline(List.of(alwaysSuccessApp(), unavailableWechat()));

        JobRecord job = new JobRecord();
        job.setPayloadJson("{\"notificationId\":100}");
        pipeline.executeNotificationSend(job);

        NotifDelivery delivery = store.values().iterator().next();
        assertEquals(DeliveryStatus.DELIVERED, delivery.getStatus());
        assertEquals(NotificationChannel.APP, delivery.getChannel());
        assertNotNull(delivery.getDeliveredAt());
    }

    private Notification notification(String priority) {
        NotificationTargetScopeDto scope = new NotificationTargetScopeDto();
        scope.setGradeId(1L);

        Notification notification = new Notification();
        notification.setId(100L);
        notification.setEventType("SCHEDULE_CHANGE");
        notification.setPriority(priority);
        notification.setStatus(NotificationStatus.SENDING);
        notification.setTitle("Title");
        notification.setBody("Body");
        notification.setTargetScope(scopeParser.toJson(scope));
        return notification;
    }

    private SysUser student(Long userId, String deviceToken) {
        SysRole role = new SysRole();
        role.setName("STUDENT");
        SysUser user = new SysUser();
        user.setId(userId);
        user.setUsername("s" + userId);
        user.setDeviceToken(deviceToken);
        user.setRoles(Set.of(role));
        return user;
    }

    private NotifPreference pref(boolean enabled, LocalTime start, LocalTime end) {
        NotifPreference pref = new NotifPreference();
        pref.setEnabled(enabled);
        pref.setDndStart(start);
        pref.setDndEnd(end);
        return pref;
    }

    private NotificationDeliveryStrategy alwaysSuccessApp() {
        return new NotificationDeliveryStrategy() {
            @Override public NotificationChannel channel() { return NotificationChannel.APP; }
            @Override public boolean supports(SysUser user) { return true; }
            @Override public DeliveryAttemptResult deliver(Notification notification, NotifDelivery delivery, SysUser user) {
                return DeliveryAttemptResult.success();
            }
        };
    }

    private NotificationDeliveryStrategy alwaysFailApp() {
        return new NotificationDeliveryStrategy() {
            @Override public NotificationChannel channel() { return NotificationChannel.APP; }
            @Override public boolean supports(SysUser user) { return true; }
            @Override public DeliveryAttemptResult deliver(Notification notification, NotifDelivery delivery, SysUser user) {
                return DeliveryAttemptResult.failed("app failure");
            }
        };
    }

    private NotificationDeliveryStrategy unavailableWechat() {
        return new NotificationDeliveryStrategy() {
            @Override public NotificationChannel channel() { return NotificationChannel.WECHAT; }
            @Override public boolean supports(SysUser user) { return user.getDeviceToken() != null; }
            @Override public DeliveryAttemptResult deliver(Notification notification, NotifDelivery delivery, SysUser user) {
                return DeliveryAttemptResult.unavailable("wechat down");
            }
        };
    }
}

